syntax = "proto3";
package service.v1;

import "google/protobuf/wrappers.proto";

// Service definition for ServiceV1
service ServiceV1 {
  // Lookup Dependency entity by id
  rpc LookupDependencyById(LookupDependencyByIdRequest) returns (LookupDependencyByIdResponse) {}
  // Lookup SBOM entity by id
  rpc LookupSBOMById(LookupSBOMByIdRequest) returns (LookupSBOMByIdResponse) {}
  rpc QueryDependency(QueryDependencyRequest) returns (QueryDependencyResponse) {}
  rpc QueryDependencyTree(QueryDependencyTreeRequest) returns (QueryDependencyTreeResponse) {}
  rpc QuerySbom(QuerySbomRequest) returns (QuerySbomResponse) {}
  rpc QueryVulnerableDependencies(QueryVulnerableDependenciesRequest) returns (QueryVulnerableDependenciesResponse) {}
}

// Key message for SBOM entity lookup
message LookupSBOMByIdRequestKey {
  // Key field for SBOM entity lookup.
  string id = 1;
}

// Request message for SBOM entity lookup.
message LookupSBOMByIdRequest {
  /*
   * List of keys to look up SBOM entities.
   * Order matters - each key maps to one entity in LookupSBOMByIdResponse.
   */
  repeated LookupSBOMByIdRequestKey keys = 1;
}

// Response message for SBOM entity lookup.
message LookupSBOMByIdResponse {
  /*
   * List of SBOM entities in the same order as the keys in LookupSBOMByIdRequest.
   * Always return the same number of entities as keys. Use null for entities that cannot be found.
   * 
   * Example:
   *   LookupUserByIdRequest:
   *     keys:
   *       - id: 1
   *       - id: 2
   *   LookupUserByIdResponse:
   *     result:
   *       - id: 1 # User with id 1 found
   *       - null  # User with id 2 not found
   */
  repeated SBOM result = 1;
}

// Key message for Dependency entity lookup
message LookupDependencyByIdRequestKey {
  // Key field for Dependency entity lookup.
  string id = 1;
}

// Request message for Dependency entity lookup.
message LookupDependencyByIdRequest {
  /*
   * List of keys to look up Dependency entities.
   * Order matters - each key maps to one entity in LookupDependencyByIdResponse.
   */
  repeated LookupDependencyByIdRequestKey keys = 1;
}

// Response message for Dependency entity lookup.
message LookupDependencyByIdResponse {
  /*
   * List of Dependency entities in the same order as the keys in LookupDependencyByIdRequest.
   * Always return the same number of entities as keys. Use null for entities that cannot be found.
   * 
   * Example:
   *   LookupUserByIdRequest:
   *     keys:
   *       - id: 1
   *       - id: 2
   *   LookupUserByIdResponse:
   *     result:
   *       - id: 1 # User with id 1 found
   *       - null  # User with id 2 not found
   */
  repeated Dependency result = 1;
}

// Request message for sbom operation.
message QuerySbomRequest {
  string repo_id = 1;
}
// Response message for sbom operation.
message QuerySbomResponse {
  SBOM sbom = 1;
}
// Request message for dependencyTree operation.
message QueryDependencyTreeRequest {
  string repo_id = 1;
  google.protobuf.Int32Value depth = 2;
}
// Response message for dependencyTree operation.
message QueryDependencyTreeResponse {
  repeated Dependency dependency_tree = 1;
}
// Request message for vulnerableDependencies operation.
message QueryVulnerableDependenciesRequest {
  string cve_id = 1;
}
// Response message for vulnerableDependencies operation.
message QueryVulnerableDependenciesResponse {
  repeated Dependency vulnerable_dependencies = 1;
}
// Request message for dependency operation.
message QueryDependencyRequest {
  string id = 1;
}
// Response message for dependency operation.
message QueryDependencyResponse {
  Dependency dependency = 1;
}

message SBOM {
  string id = 1;
  string repo_id = 2;
  string generated_at = 3;
  google.protobuf.StringValue signed_by = 4;
  google.protobuf.StringValue sigstore_bundle_url = 5;
  google.protobuf.Int32Value slsa_level = 6;
  int32 component_count = 7;
  repeated Dependency components = 8;
}

message Dependency {
  string id = 1;
  string name = 2;
  string version = 3;
  string ecosystem = 4;
  bool transitive = 5;
  int32 depth = 6;
  google.protobuf.StringValue license = 7;
  google.protobuf.StringValue parent_id = 8;
  google.protobuf.StringValue sha_256 = 9;
}

syntax = "proto3";
package service.v1;

import "google/protobuf/wrappers.proto";

// Service definition for ServiceV1
service ServiceV1 {
  // Lookup Deployment entity by id
  rpc LookupDeploymentById(LookupDeploymentByIdRequest) returns (LookupDeploymentByIdResponse) {}
  rpc MutationRollout(MutationRolloutRequest) returns (MutationRolloutResponse) {}
  rpc MutationStageDeployment(MutationStageDeploymentRequest) returns (MutationStageDeploymentResponse) {}
  rpc QueryActiveVersion(QueryActiveVersionRequest) returns (QueryActiveVersionResponse) {}
  rpc QueryDeployment(QueryDeploymentRequest) returns (QueryDeploymentResponse) {}
  rpc QueryDeployments(QueryDeploymentsRequest) returns (QueryDeploymentsResponse) {}
}

// Key message for Deployment entity lookup
message LookupDeploymentByIdRequestKey {
  // Key field for Deployment entity lookup.
  string id = 1;
}

// Request message for Deployment entity lookup.
message LookupDeploymentByIdRequest {
  /*
   * List of keys to look up Deployment entities.
   * Order matters - each key maps to one entity in LookupDeploymentByIdResponse.
   */
  repeated LookupDeploymentByIdRequestKey keys = 1;
}

// Response message for Deployment entity lookup.
message LookupDeploymentByIdResponse {
  /*
   * List of Deployment entities in the same order as the keys in LookupDeploymentByIdRequest.
   * Always return the same number of entities as keys. Use null for entities that cannot be found.
   * 
   * Example:
   *   LookupUserByIdRequest:
   *     keys:
   *       - id: 1
   *       - id: 2
   *   LookupUserByIdResponse:
   *     result:
   *       - id: 1 # User with id 1 found
   *       - null  # User with id 2 not found
   */
  repeated Deployment result = 1;
}

// Request message for deployments operation.
message QueryDeploymentsRequest {
  string repo_id = 1;
}
// Response message for deployments operation.
message QueryDeploymentsResponse {
  repeated Deployment deployments = 1;
}
// Request message for deployment operation.
message QueryDeploymentRequest {
  string id = 1;
}
// Response message for deployment operation.
message QueryDeploymentResponse {
  Deployment deployment = 1;
}
// Request message for activeVersion operation.
message QueryActiveVersionRequest {
  string service = 1;
  string environment = 2;
}
// Response message for activeVersion operation.
message QueryActiveVersionResponse {
  google.protobuf.StringValue active_version = 1;
}
// Request message for stageDeployment operation.
message MutationStageDeploymentRequest {
  StageDeploymentInput input = 1;
}
// Response message for stageDeployment operation.
message MutationStageDeploymentResponse {
  Deployment stage_deployment = 1;
}
// Request message for rollout operation.
message MutationRolloutRequest {
  string deployment_id = 1;
}
// Response message for rollout operation.
message MutationRolloutResponse {
  DeploymentResult rollout = 1;
}

message Deployment {
  string id = 1;
  string repo_id = 2;
  string environment = 3;
  string version = 4;
  string deployed_at = 5;
  string deployed_by = 6;
  repeated string affected_services = 7;
  string status = 8;
  google.protobuf.StringValue sbom_id = 9;
  google.protobuf.StringValue hypothesis_id = 10;
}

message StageDeploymentInput {
  string repo_id = 1;
  string version = 2;
  google.protobuf.StringValue hypothesis_id = 3;
  repeated string affected_services = 4;
}

message DeploymentResult {
  string deployment_id = 1;
  bool success = 2;
  string message = 3;
  bool approval_required = 4;
}

syntax = "proto3";
package service.v1;

import "google/protobuf/wrappers.proto";

// Service definition for ServiceV1
service ServiceV1 {
  // Lookup CVE entity by id
  rpc LookupCVEById(LookupCVEByIdRequest) returns (LookupCVEByIdResponse) {}
  // Lookup Dependency entity by id
  rpc LookupDependencyById(LookupDependencyByIdRequest) returns (LookupDependencyByIdResponse) {}
  rpc QueryBlastRadius(QueryBlastRadiusRequest) returns (QueryBlastRadiusResponse) {}
  rpc QueryCve(QueryCveRequest) returns (QueryCveResponse) {}
  rpc QueryCvesBySeverity(QueryCvesBySeverityRequest) returns (QueryCvesBySeverityResponse) {}
  rpc QueryCvesForDependency(QueryCvesForDependencyRequest) returns (QueryCvesForDependencyResponse) {}
  rpc QueryRiskScore(QueryRiskScoreRequest) returns (QueryRiskScoreResponse) {}
}

// Key message for CVE entity lookup
message LookupCVEByIdRequestKey {
  // Key field for CVE entity lookup.
  string id = 1;
}

// Request message for CVE entity lookup.
message LookupCVEByIdRequest {
  /*
   * List of keys to look up CVE entities.
   * Order matters - each key maps to one entity in LookupCVEByIdResponse.
   */
  repeated LookupCVEByIdRequestKey keys = 1;
}

// Response message for CVE entity lookup.
message LookupCVEByIdResponse {
  /*
   * List of CVE entities in the same order as the keys in LookupCVEByIdRequest.
   * Always return the same number of entities as keys. Use null for entities that cannot be found.
   * 
   * Example:
   *   LookupUserByIdRequest:
   *     keys:
   *       - id: 1
   *       - id: 2
   *   LookupUserByIdResponse:
   *     result:
   *       - id: 1 # User with id 1 found
   *       - null  # User with id 2 not found
   */
  repeated CVE result = 1;
}

// Key message for Dependency entity lookup
message LookupDependencyByIdRequestKey {
  // Key field for Dependency entity lookup.
  string id = 1;
}

// Request message for Dependency entity lookup.
message LookupDependencyByIdRequest {
  /*
   * List of keys to look up Dependency entities.
   * Order matters - each key maps to one entity in LookupDependencyByIdResponse.
   */
  repeated LookupDependencyByIdRequestKey keys = 1;
}

// Response message for Dependency entity lookup.
message LookupDependencyByIdResponse {
  /*
   * List of Dependency entities in the same order as the keys in LookupDependencyByIdRequest.
   * Always return the same number of entities as keys. Use null for entities that cannot be found.
   * 
   * Example:
   *   LookupUserByIdRequest:
   *     keys:
   *       - id: 1
   *       - id: 2
   *   LookupUserByIdResponse:
   *     result:
   *       - id: 1 # User with id 1 found
   *       - null  # User with id 2 not found
   */
  repeated Dependency result = 1;
}

// Request message for cve operation.
message QueryCveRequest {
  string id = 1;
}
// Response message for cve operation.
message QueryCveResponse {
  CVE cve = 1;
}
// Request message for cvesBySeverity operation.
message QueryCvesBySeverityRequest {
  double min_score = 1;
}
// Response message for cvesBySeverity operation.
message QueryCvesBySeverityResponse {
  repeated CVE cves_by_severity = 1;
}
// Request message for riskScore operation.
message QueryRiskScoreRequest {
  string cve_id = 1;
  string repo_id = 2;
}
// Response message for riskScore operation.
message QueryRiskScoreResponse {
  RiskScore risk_score = 1;
}
// Request message for blastRadius operation.
message QueryBlastRadiusRequest {
  string cve_id = 1;
  string repo_id = 2;
}
// Response message for blastRadius operation.
message QueryBlastRadiusResponse {
  BlastRadius blast_radius = 1;
}
// Request message for cvesForDependency operation.
message QueryCvesForDependencyRequest {
  string dependency_id = 1;
}
// Response message for cvesForDependency operation.
message QueryCvesForDependencyResponse {
  repeated CVE cves_for_dependency = 1;
}

message CVE {
  string id = 1;
  double cvss_score = 2;
  Severity severity = 3;
  string published_at = 4;
  string description = 5;
  repeated string affected_packages = 6;
  bool exploit_in_wild = 7;
  google.protobuf.StringValue nvd_url = 8;
}

message Dependency {
  string id = 1;
  repeated CVE risks = 2;
  DependencyRiskSummary risk_summary = 3;
}

message RiskScore {
  string cve_id = 1;
  string repo_id = 2;
  double score = 3;
  string reasoning = 4;
  int32 affected_component_count = 5;
  int32 transitive_impact = 6;
}

message BlastRadius {
  string cve_id = 1;
  string repo_id = 2;
  int32 services_affected = 3;
  int32 transitive_depth = 4;
  int32 estimated_users = 5;
  repeated string critical_path = 6;
}

message DependencyRiskSummary {
  string dependency_id = 1;
  double max_cvss_score = 2;
  int32 critical_count = 3;
  int32 high_count = 4;
  int32 total_count = 5;
}

enum Severity {
  SEVERITY_UNSPECIFIED = 0;
  SEVERITY_CRITICAL = 1;
  SEVERITY_HIGH = 2;
  SEVERITY_MEDIUM = 3;
  SEVERITY_LOW = 4;
  SEVERITY_INFORMATIONAL = 5;
}

syntax = "proto3";
package service.v1;

import "google/protobuf/wrappers.proto";

// Service definition for ServiceV1
service ServiceV1 {
  // Lookup CVE entity by id
  rpc LookupCVEById(LookupCVEByIdRequest) returns (LookupCVEByIdResponse) {}
  rpc QueryPatchProviders(QueryPatchProvidersRequest) returns (QueryPatchProvidersResponse) {}
  rpc QueryRecommendedStrategy(QueryRecommendedStrategyRequest) returns (QueryRecommendedStrategyResponse) {}
  rpc QueryRemediationOptions(QueryRemediationOptionsRequest) returns (QueryRemediationOptionsResponse) {}
  rpc QueryX402Listings(QueryX402ListingsRequest) returns (QueryX402ListingsResponse) {}
}

// Key message for CVE entity lookup
message LookupCVEByIdRequestKey {
  // Key field for CVE entity lookup.
  string id = 1;
}

// Request message for CVE entity lookup.
message LookupCVEByIdRequest {
  /*
   * List of keys to look up CVE entities.
   * Order matters - each key maps to one entity in LookupCVEByIdResponse.
   */
  repeated LookupCVEByIdRequestKey keys = 1;
}

// Response message for CVE entity lookup.
message LookupCVEByIdResponse {
  /*
   * List of CVE entities in the same order as the keys in LookupCVEByIdRequest.
   * Always return the same number of entities as keys. Use null for entities that cannot be found.
   * 
   * Example:
   *   LookupUserByIdRequest:
   *     keys:
   *       - id: 1
   *       - id: 2
   *   LookupUserByIdResponse:
   *     result:
   *       - id: 1 # User with id 1 found
   *       - null  # User with id 2 not found
   */
  repeated CVE result = 1;
}

// Request message for remediationOptions operation.
message QueryRemediationOptionsRequest {
  string cve_id = 1;
}
// Response message for remediationOptions operation.
message QueryRemediationOptionsResponse {
  repeated RemediationOption remediation_options = 1;
}
// Request message for patchProviders operation.
message QueryPatchProvidersRequest {
  string package_name = 1;
}
// Response message for patchProviders operation.
message QueryPatchProvidersResponse {
  repeated PatchProvider patch_providers = 1;
}
// Request message for x402Listings operation.
message QueryX402ListingsRequest {
  string for_cve_id = 1;
}
// Response message for x402Listings operation.
message QueryX402ListingsResponse {
  repeated X402Listing x_402_listings = 1;
}
// Request message for recommendedStrategy operation.
message QueryRecommendedStrategyRequest {
  string cve_id = 1;
}
// Response message for recommendedStrategy operation.
message QueryRecommendedStrategyResponse {
  RemediationOption recommended_strategy = 1;
}

message CVE {
  string id = 1;
  repeated RemediationOption remediation_options = 2;
  RemediationOption recommended_remediation = 3;
}

message RemediationOption {
  string id = 1;
  string cve_id = 2;
  RemediationStrategy strategy = 3;
  google.protobuf.StringValue target_version = 4;
  google.protobuf.StringValue target_image = 5;
  double confidence = 6;
  string provider = 7;
  double cost_usd = 8;
  string description = 9;
  X402Listing x_402_listing = 10;
}

message PatchProvider {
  string name = 1;
  string url = 2;
  bool verified = 3;
  bool sbom_signed = 4;
}

message X402Listing {
  string id = 1;
  string provider_url = 2;
  double price_usd = 3;
  string description = 4;
  repeated string accepted_networks = 5;
}

enum RemediationStrategy {
  REMEDIATION_STRATEGY_UNSPECIFIED = 0;
  REMEDIATION_STRATEGY_UPGRADE = 1;
  REMEDIATION_STRATEGY_PIN = 2;
  REMEDIATION_STRATEGY_CHAINGUARD_SWAP = 3;
  REMEDIATION_STRATEGY_VENDOR_PATCH = 4;
  REMEDIATION_STRATEGY_ROLLBACK = 5;
}
